# Create a CA policy: require MFA for all users accessing Azure management
# Start in Report-Only to measure impact before enabling
# Requires Policy.ReadWrite.ConditionalAccess
$policy = @{
    displayName = 'Require MFA for Azure management'
    state       = 'enabledForReportingButNotEnforcing'
    conditions  = @{
        users = @{
            includeUsers  = @('All')
            excludeGroups = @('<break-glass-group-oid>')
        }
        applications = @{
            includeApplications = @('797f4846-ba00-4fd7-ba43-dac1f8f63013')
        }
        clientAppTypes = @('browser', 'mobileAppsAndDesktopClients')
    }
    grantControls = @{
        operator        = 'OR'
        builtInControls = @('mfa')
    }
} | ConvertTo-Json -Depth 8

$result = Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' \
  -Body $policy -ContentType 'application/json'
Write-Host "Created policy: $($result.id)"

# After testing in Report-Only, enable the policy
Invoke-MgGraphRequest -Method PATCH \
  -Uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies/$($result.id)" \
  -Body '{"state": "enabled"}' -ContentType 'application/json'

# AND: require MFA AND compliant device (both required)
grantControls = @{
    operator        = 'AND'
    builtInControls = @('mfa', 'compliantDevice')
}

# OR: require MFA OR compliant device (either satisfies the policy)
grantControls = @{
    operator        = 'OR'
    builtInControls = @('mfa', 'compliantDevice')
}

# Combine built-in controls with custom authentication strength
grantControls = @{
    operator           = 'AND'
    builtInControls    = @('compliantDevice')
    authenticationStrength = @{ id = '<phishing-resistant-strength-id>' }
}

# Pattern: always exclude break-glass group from CA policies
conditions = @{
    users = @{
        includeUsers  = @('All')
        excludeGroups = @('<break-glass-group-oid>')
    }
}

# Monitor break-glass account sign-ins in Log Analytics
# Alert if any break-glass account signs in (should be near-zero in normal ops)

# KQL for Sentinel alert:
# SigninLogs
# | where UserPrincipalName in ('<breakglass1@contoso.com>', '<breakglass2@contoso.com>')
# | project TimeGenerated, UserPrincipalName, AppDisplayName, IPAddress, ResultType

# Manage CA policies with azuread Terraform provider
resource "azuread_conditional_access_policy" "require_mfa_azure_mgmt" {
  display_name = "Require MFA for Azure management"
  state        = "enabled"

  conditions {
    users {
      included_users  = ["All"]
      excluded_groups = [azuread_group.break_glass.id]
    }
    applications {
      included_applications = ["797f4846-ba00-4fd7-ba43-dac1f8f63013"]
    }
    client_app_types = ["browser", "mobileAppsAndDesktopClients"]
  }

  grant_controls {
    operator          = "OR"
    built_in_controls = ["mfa"]
  }
}

# Use for_each to deploy a standard policy set across all environments
variable "ca_policy_state" {
  default = "enabledForReportingButNotEnforcing"
  description = "Override to enabled after validation"
}

# Target a CA policy at specific directory roles (e.g., all privileged admins)
conditions = @{
    users = @{
        includeRoles = @(
            '62e90394-69f5-4237-9190-012177145e10',  # Global Administrator
            '194ae4cb-b126-40b2-bd5b-6091b380977d',  # Security Administrator
            'f28a1f50-f6e7-4571-818b-6a12f2af6b6c',  # SharePoint Administrator
            '29232cdf-9323-42fd-ade2-1d097af3e4de',  # Exchange Administrator
            'b0f54661-2d74-4c50-afa3-1ec803f12efe'   # Billing Administrator
        )
        excludeGroups = @('<break-glass-group-oid>')
    }
    applications = @{ includeApplications = @('All') }
    clientAppTypes = @('browser', 'mobileAppsAndDesktopClients')
}

# Note: role IDs are tenant-independent built-in role template IDs
# Get them via: Get-MgDirectoryRole | Select-Object DisplayName, RoleTemplateId

# Target workload identities (service principals) — requires separate CA policy type
# Use identities.servicePrincipals scope (preview/GA depending on tenant)

# Retrieve detailed CA policy results for a specific user's recent sign-ins
$upn = 'alice@contoso.com'
$signIns = Invoke-MgGraphRequest -Method GET \
  -Uri "https://graph.microsoft.com/v1.0/auditLogs/signIns?`$filter=userPrincipalName eq '$upn'&`$top=10&`$orderby=createdDateTime desc"

foreach ($signIn in $signIns.value) {
    Write-Host "App: $($signIn.appDisplayName)  Time: $($signIn.createdDateTime)  Result: $($signIn.status.errorCode)"
    foreach ($policy in $signIn.conditionalAccessPolicies) {
        Write-Host "  Policy: $($policy.displayName)"
        Write-Host "    Result: $($policy.result)"
        if ($policy.enforcedGrantControls) {
            Write-Host "    Required: $($policy.enforcedGrantControls -join ', ')"
        }
    }
}

# Enable Continuous Access Evaluation in a CA policy session control
sessionControls = @{
    continuousAccessEvaluation = @{
        mode = 'strictLocation'
        # strictLocation: revoke token if user moves outside named locations
        # disabled: opt out of CAE for this policy
        # strictEnforcement (default): revoke on critical events (disable, password change, session revoke)
    }
}

# CAE-capable apps (as of 2024): Exchange Online, SharePoint Online,
# Microsoft Teams, Microsoft Graph, Azure Management

# Verify if a sign-in used CAE (isCaeEligible in sign-in logs)
$recent = Invoke-MgGraphRequest -Method GET \
  -Uri 'https://graph.microsoft.com/v1.0/auditLogs/signIns?$top=5'
$recent.value | Select-Object userPrincipalName, appDisplayName, @{N="CAE";E={$_.isCaeEligible}}
